// 解析Webhook请求参数
const inputData = $input.all();
const requestBody = inputData[0].json.body;

console.log('=== 解析请求参数 ===');
console.log('请求体:', requestBody);

// 提取参数
const {
  startDate = '20250901',
  endDate = '20250930',
  startMonth = '202509',
  endMonth = '202510',
  merchantId = null,
  gameId = null,
  statType = 'all' // 'merchant_daily', 'merchant_monthly', 'game_daily', 'game_monthly', 'all'
} = requestBody;

// 验证日期格式
function validateDateFormat(dateStr) {
  return /^\d{8}$/.test(dateStr);
}

function validateMonthFormat(monthStr) {
  return /^\d{6}$/.test(monthStr);
}

// 参数验证
if (!validateDateFormat(startDate) || !validateDateFormat(endDate)) {
  throw new Error('日期格式错误，应为YYYYMMDD格式');
}

if (!validateMonthFormat(startMonth) || !validateMonthFormat(endMonth)) {
  throw new Error('月份格式错误，应为YYYYMM格式');
}

// 构建SQL查询条件
let whereConditions = [];
let orderByClause = '';

// 根据统计类型构建查询条件
if (statType === 'all') {
  whereConditions.push(`(
    (stat_type IN ('merchant_daily', 'game_daily') 
     AND date_str >= '${startDate}' 
     AND date_str <= '${endDate}')
    OR 
    (stat_type IN ('merchant_monthly', 'game_monthly') 
     AND month_str >= '${startMonth}' 
     AND month_str <= '${endMonth}')
  )`);
  orderByClause = 'ORDER BY stat_type, month_str, date_str, merchant, game_id';
} else {
  if (statType.includes('daily')) {
    whereConditions.push(`stat_type = '${statType}'`);
    whereConditions.push(`date_str >= '${startDate}'`);
    whereConditions.push(`date_str <= '${endDate}'`);
    orderByClause = 'ORDER BY date_str, merchant, game_id';
  } else if (statType.includes('monthly')) {
    whereConditions.push(`stat_type = '${statType}'`);
    whereConditions.push(`month_str >= '${startMonth}'`);
    whereConditions.push(`month_str <= '${endMonth}'`);
    orderByClause = 'ORDER BY month_str, merchant, game_id';
  }
}

// 添加商户ID过滤条件
if (merchantId) {
  whereConditions.push(`merchant = '${merchantId}'`);
}

// 添加游戏ID过滤条件
if (gameId) {
  whereConditions.push(`game_id = '${gameId}'`);
}

// 构建完整SQL查询
const sqlQuery = `
SELECT 
    stat_type,
    date_str,
    month_str,
    merchant,
    game_id,
    unique_users
FROM merchant_game_analytics
WHERE ${whereConditions.join(' AND ')}
${orderByClause};
`;

console.log('=== 构建的SQL查询 ===');
console.log(sqlQuery);

// 返回查询参数
return {
  json: {
    sqlQuery: sqlQuery.trim(),
    parameters: {
      startDate,
      endDate,
      startMonth,
      endMonth,
      merchantId,
      gameId,
      statType
    },
    whereConditions: whereConditions,
    orderByClause: orderByClause
  }
};

// 处理查询结果
const inputData = $input.all();
const queryResult = inputData[0].json;

console.log('=== 处理查询结果 ===');
console.log('查询结果:', queryResult);

// 检查查询是否成功
if (!queryResult.success) {
  throw new Error(`查询失败: ${queryResult.error || '未知错误'}`);
}

const data = queryResult.data || [];
const rowCount = queryResult.rowCount || 0;

console.log(`查询成功，返回 ${rowCount} 条记录`);

// 按统计类型分组数据
const groupedData = {
  merchant_daily: [],
  merchant_monthly: [],
  game_daily: [],
  game_monthly: []
};

// 分组数据
data.forEach(row => {
  const statType = row.stat_type;
  if (groupedData[statType]) {
    groupedData[statType].push(row);
  }
});

// 计算汇总统计
const summary = {
  total_records: rowCount,
  merchant_daily_count: groupedData.merchant_daily.length,
  merchant_monthly_count: groupedData.merchant_monthly.length,
  game_daily_count: groupedData.game_daily.length,
  game_monthly_count: groupedData.game_monthly.length,
  total_unique_users: data.reduce((sum, row) => sum + (row.unique_users || 0), 0)
};

// 按商户汇总
const merchantSummary = {};
data.forEach(row => {
  if (row.merchant) {
    if (!merchantSummary[row.merchant]) {
      merchantSummary[row.merchant] = {
        merchant: row.merchant,
        total_unique_users: 0,
        daily_records: 0,
        monthly_records: 0
      };
    }
    merchantSummary[row.merchant].total_unique_users += row.unique_users || 0;
    if (row.stat_type.includes('daily')) {
      merchantSummary[row.merchant].daily_records++;
    } else if (row.stat_type.includes('monthly')) {
      merchantSummary[row.merchant].monthly_records++;
    }
  }
});

console.log('=== 汇总统计 ===');
console.log('总记录数:', summary.total_records);
console.log('总唯一用户数:', summary.total_unique_users);
console.log('商户汇总:', Object.keys(merchantSummary).length, '个商户');

// 返回处理后的结果
return {
  json: {
    success: true,
    summary: summary,
    merchantSummary: Object.values(merchantSummary),
    groupedData: groupedData,
    rawData: data,
    queryInfo: {
      rowCount: rowCount,
      executionTime: queryResult.executionTime || 0,
      queryId: queryResult.queryId
    }
  }
};

// 格式化输出结果
const inputData = $input.all();
const processedData = inputData[0].json;

console.log('=== 格式化输出结果 ===');

const { summary, merchantSummary, groupedData, rawData, queryInfo } = processedData;

// 构建响应消息
let responseMessage = `📊 **商户游戏分析查询结果**\n\n`;

// 汇总信息
responseMessage += `📈 **汇总统计**\n`;
responseMessage += `• 总记录数: ${summary.total_records}\n`;
responseMessage += `• 总唯一用户数: ${summary.total_unique_users.toLocaleString()}\n`;
responseMessage += `• 商户维度每日记录: ${summary.merchant_daily_count}\n`;
responseMessage += `• 商户维度月度记录: ${summary.merchant_monthly_count}\n`;
responseMessage += `• 游戏维度每日记录: ${summary.game_daily_count}\n`;
responseMessage += `• 游戏维度月度记录: ${summary.game_monthly_count}\n\n`;

// 商户汇总
if (merchantSummary.length > 0) {
  responseMessage += `🏢 **商户汇总**\n`;
  merchantSummary.slice(0, 10).forEach(merchant => {
    responseMessage += `• 商户 ${merchant.merchant}: ${merchant.total_unique_users.toLocaleString()} 唯一用户\n`;
  });
  if (merchantSummary.length > 10) {
    responseMessage += `• ... 还有 ${merchantSummary.length - 10} 个商户\n`;
  }
  responseMessage += `\n`;
}

// 查询信息
responseMessage += `🔍 **查询信息**\n`;
responseMessage += `• 查询ID: ${queryInfo.queryId}\n`;
responseMessage += `• 执行时间: ${queryInfo.executionTime}ms\n`;
responseMessage += `• 返回记录: ${queryInfo.rowCount}\n`;

// 如果有数据，提供下载链接
if (rawData.length > 0) {
  responseMessage += `\n📥 **数据下载**\n`;
  responseMessage += `• 数据已导出，可通过查询ID下载详细结果\n`;
}

console.log('响应消息长度:', responseMessage.length);

// 返回格式化结果
return {
  json: {
    success: true,
    message: responseMessage,
    summary: summary,
    merchantSummary: merchantSummary,
    queryInfo: queryInfo,
    hasData: rawData.length > 0,
    dataCount: rawData.length
  }
};
